s = ''.join(paren_string.split())
res: List[str] = []
stack = []
start = None

for i, ch in enumerate(s):
    if ch == '(':
        if not stack:
            start = i
        stack.append('(')
    elif ch == ')':
        if stack:
            stack.pop()
        if not stack and start is not None:
            res.append(s[start:i+1])
            start = None

return res
